import{_ as t,a as e,b as d,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as n,o as c,c as p,a2 as u}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Резервне дублювання та перемикання джерела читання","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Other/redundant-backup-and-read-source.md","filePath":"uk-UA/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),h={name:"uk-UA/Other/redundant-backup-and-read-source.md"};function l(o,a,i,s,b,k){return c(),p("div",null,[...a[0]||(a[0]=[u('<h1 id="резервне-дублювання-та-перемикання-джерела-читання" tabindex="-1">Резервне дублювання та перемикання джерела читання <a class="header-anchor" href="#резервне-дублювання-та-перемикання-джерела-читання" aria-label="Permalink to &quot;Резервне дублювання та перемикання джерела читання&quot;">​</a></h1><p>Redundant backup зберігає додаткову копію вже завантаженого файлу.</p><p>І основний файл, і backup file можуть використовуватися як read sources. Для відвідувачів зазвичай немає різниці. Відрізняється лише storage channel, з якого віддається файл.</p><h2 id="що-може-redundant-backup" tabindex="-1">Що може Redundant Backup <a class="header-anchor" href="#що-може-redundant-backup" aria-label="Permalink to &quot;Що може Redundant Backup&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Можливість</th><th>Опис</th></tr></thead><tbody><tr><td>Зберігати додаткову копію</td><td>Резервує файли в інший upload channel, щоб зменшити ризик відмови одного каналу.</td></tr><tr><td>Перемикати read source</td><td>Після успішного backup перемикає читання файлу між primary channel і backup channel.</td></tr><tr><td>Single-file backup</td><td>Резервує один файл зі сторінки деталей файлу.</td></tr><tr><td>Batch backup</td><td>Вибирає кілька файлів в адмін-панелі й резервує їх разом.</td></tr><tr><td>Global redundant backup</td><td>Резервує файли за папкою з Other Settings.</td></tr></tbody></table><h2 id="вхід-redundant-backup" tabindex="-1">Вхід Redundant Backup <a class="header-anchor" href="#вхід-redundant-backup" aria-label="Permalink to &quot;Вхід Redundant Backup&quot;">​</a></h2><p>Відкрийте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+t+'" alt="Redundant backup" loading="lazy"></p><p>Цей вхід найкраще підходить для масового додавання backup до папки або до всіх файлів.</p><p>Backup channel можна вибрати вручну, або можна ввімкнути automatic switching і дозволити ImgBed знайти придатний backup channel.</p><h2 id="backup-зі-сторінки-деталеи-фаилу" tabindex="-1">Backup зі сторінки деталей файлу <a class="header-anchor" href="#backup-зі-сторінки-деталеи-фаилу" aria-label="Permalink to &quot;Backup зі сторінки деталей файлу&quot;">​</a></h2><p>Відкрийте сторінку деталей файлу в адмін-панелі й натисніть backup.</p><p><img src="'+e+'" alt="Backup у деталях файлу" loading="lazy"></p><p>Це найкраще для резервування одного важливого файлу на вимогу.</p><p>Після успішного backup сторінка деталей файлу показує доступні read sources.</p><h2 id="batch-backup-за-вибором" tabindex="-1">Batch Backup за вибором <a class="header-anchor" href="#batch-backup-за-вибором" aria-label="Permalink to &quot;Batch Backup за вибором&quot;">​</a></h2><p>В адмін-панелі виберіть кілька файлів і запустіть batch backup.</p><p><img src="'+d+'" alt="Batch backup" loading="lazy"></p><p>Це зручно для обробки групи файлів.</p><p>Selection backup, file details backup і redundant backup в Other Settings використовують одну й ту саму backup system. Це просто різні точки входу.</p><h2 id="перемикання-read-source-після-backup" tabindex="-1">Перемикання Read Source після backup <a class="header-anchor" href="#перемикання-read-source-після-backup" aria-label="Permalink to &quot;Перемикання Read Source після backup&quot;">​</a></h2><p>Після завершення backup сторінка деталей файлу дозволяє перемкнути read source:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Опис</th></tr></thead><tbody><tr><td>Primary channel</td><td>Читання з початкового upload channel.</td></tr><tr><td>Backup channel</td><td>Читання з backup channel.</td></tr></tbody></table><p><img src="'+r+'" alt="Перемикання read source після backup" loading="lazy"></p><p>Відвідувачам не потрібно знати, чи файл віддається з primary, чи з backup channel.</p><p>Вибране read source стає пріоритетним для подальшого доступу до файлу.</p><h2 id="коли-backup-пропускається" tabindex="-1">Коли Backup пропускається <a class="header-anchor" href="#коли-backup-пропускається" aria-label="Permalink to &quot;Коли Backup пропускається&quot;">​</a></h2><p>Під час backup такі випадки пропускаються. Це не помилки.</p><table tabindex="0"><thead><tr><th>Випадок</th><th>Чому пропускається</th></tr></thead><tbody><tr><td>Already backed up</td><td>Файл, який уже має backup, не резервується повторно.</td></tr><tr><td>Primary and backup channels are the same</td><td>Backup має зберігатися в іншому channel, інакше він не має сенсу.</td></tr><tr><td>No usable backup channel</td><td>Немає придатного альтернативного channel.</td></tr></tbody></table><p>Коротко: backups мають іти в інший channel, а вже зарезервовані файли не витрачають місце повторно.</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Назва</th><th>Значення</th></tr></thead><tbody><tr><td>Primary channel</td><td>Channel, через який файл було завантажено вперше.</td></tr><tr><td>Backup channel</td><td>Channel, у якому зберігається redundant copy.</td></tr><tr><td>Primary read source</td><td>Файл зараз читається з primary channel.</td></tr><tr><td>Backup read source</td><td>Файл зараз читається з backup channel.</td></tr></tbody></table><p>Primary і backup read sources мають однакову поведінку для користувача.</p><p>Поки backup file доступний, зображення, відео й download links продовжують працювати після перемикання на backup read source.</p><h2 id="що-відбувається-під-час-видалення-фаилу" tabindex="-1">Що відбувається під час видалення файлу <a class="header-anchor" href="#що-відбувається-під-час-видалення-фаилу" aria-label="Permalink to &quot;Що відбувається під час видалення файлу&quot;">​</a></h2><p>Коли файл видаляється, ImgBed видаляє і primary file, і backup file.</p>',37)])])}const B=n(h,[["render",l]]);export{_ as __pageData,B as default};
